require"UI.UIBase"require"UI.UIBlock"UI_MJReward_Activity=UIBase:Inherit()function UI_MJReward_Activity:OnCreate()UI_MJReward_Activity.Inst=self;self.index=0;self.locking=false;self.complete=nil;self.activity_reward={}self.root=self.transform:Find('root')self.rootCanvas=self.root:GetComponent(typeof(UnityEngine.CanvasGroup))self.btn_close=self.transform:Find('btn_close'):GetComponent(typeof(UnityEngine.UI.Button))self.btn_close.gameObject:SetActive(false)self.tasks={}for a=1,3 do local b=self.root:GetChild(a-1)local c={container=b,img_item=b:Find('item'):GetComponent(typeof(UnityEngine.UI.Image)),txt_item_name=b:Find('name'):GetComponent(typeof(UnityEngine.UI.Text)),txt_item_count=b:Find('count'):GetComponent(typeof(UnityEngine.UI.Text)),txt_item_count_anim=b:Find('count'):GetComponent(typeof(anim_alpha))}table.insert(self.tasks,c)end end;function UI_MJReward_Activity:OnShow(d,e)self.locking=true;self.complete=e.callback;d()for a=1,#self.tasks do self.tasks[a].container.gameObject:SetActive(false)end;self.transform.gameObject:SetActive(true)self.index=1;self.activity_reward=e.data;self:ShowNext(self.activity_reward[self.index])end;function UI_MJReward_Activity:ShowNext(f)self.locking=true;self.rootCanvas.alpha=1;for a=1,#self.tasks do self.tasks[a].container.gameObject:SetActive(false)end;local g=f.rewards;for a=1,#self.tasks do if g[a]and g[a].id~=0 then TimeMgr.Delay(0.6*(a-1),function()self:AnimPopOut(self.tasks[a].container)local h=GameUtility.get_item_view(g[a].id)self.tasks[a].container.gameObject:SetActive(true)self.tasks[a].img_item:SetTextureAsync(h.icon)self.tasks[a].txt_item_name.text=h.name;self.tasks[a].txt_item_count.text='+'..g[a].count;self.tasks[a].txt_item_count_anim:Alpha_In()end)end end;local i=(Mathf.Min(#self.tasks,#g)+1)*0.6;TimeMgr.Delay(i,function()self.locking=false;if self.index<#self.activity_reward then self:TryClose(true)else if self.complete then self.complete()self.complete=nil end end end)end;function UI_MJReward_Activity:TryClose()self.locking=true;self:AnimAlphaOut(self.root,{x=0,y=0},0.15,0,function()self.locking=false;self.index=self.index+1;if self.index<=#self.activity_reward then self:ShowNext(self.activity_reward[self.index])else if self.complete then self.complete()self.complete=nil end end end)end;function UI_MJReward_Activity:OnClose(d)self.transform.gameObject:SetActive(false)if self.complete then self.complete()self.complete=nil end;d()end;return UI_MJReward_Activity